const raw = $input.first().json.choices[0].message.content;

let cleaned = raw.trim()
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .replace(/[\r\n]+/g, ' ')
  .replace(/\t/g, ' ')
  .trim();

let data;
try {
  data = JSON.parse(cleaned);
} catch(e) {
  const match = cleaned.match(/[\[\{][\s\S]*[\]\}]/);
  if (match) {
    try {
      data = JSON.parse(match[0]);
    } catch(e2) {
      throw new Error('JSON tidak valid: ' + cleaned.substring(0, 300));
    }
  } else {
    throw new Error('Tidak ada JSON ditemukan: ' + cleaned.substring(0, 300));
  }
}

if (!Array.isArray(data)) data = [data];

const now = new Date();

return data.map(item => {
  const tanggalStr = item.tanggal || new Date().toISOString().slice(0,10);
  const tanggal = new Date(tanggalStr);
  const hari = ['Minggu','Senin','Selasa','Rabu','Kamis','Jumat','Sabtu'][tanggal.getDay()];
  return {
    json: {
      id_transaksi: `TRX-${tanggalStr.replace(/-/g,'')}-${Math.floor(Math.random()*900000)+100000}`,
      waktu_input: now.toLocaleDateString('id-ID', {day:'2-digit', month:'long', year:'numeric'}),
      tanggal: tanggalStr,
      bulan: tanggal.getMonth() + 1,
      tahun: tanggal.getFullYear(),
      hari: hari,
      tipe: item.tipe || "",
      status: "VALID",
      kategori: item.kategori || "",
      sub_kategori: item.sub_kategori || "",
      deskripsi: item.deskripsi || "",
      nominal: Number(item.nominal) || 0,
      dompet: item.dompet || "",
      transfer_ke: item.transfer_ke || "",
      metode_bayar: item.metode_bayar || "",
      sumber_pemasukan: item.sumber_pemasukan || "",
      vendor: item.vendor || "",
      catatan: item.catatan || "",
      tag: item.tag || "",
      dibuat_oleh: String($('Telegram Trigger').first().json.message.from.id || "")
    }
  };
});

const items = $('Code in JavaScript').all().map(i => i.json);
const count = items.length;
const escape = (str) => String(str).replace(/[_*[\]()~`>#+\-=|{}.!\\]/g, '\\$&');
let text = '';
if (count <= 10) {
  const total = items.reduce((sum, i) => sum + i.nominal, 0);
  const rincian = items.map((item) => {
    let meta = '📂 ' + escape(item.kategori);
    if (item.dompet) meta += ' \\| 💳 ' + escape(item.dompet);
    if (item.sumber_pemasukan) meta += ' \\| 👤 ' + escape(item.sumber_pemasukan);
    return escape(item.deskripsi) + ' — Rp ' + escape(item.nominal.toLocaleString('id-ID')) + '\n' + meta;
  }).join('\n');
  text = '✅ ' + escape(count) + ' transaksi berhasil dicatat\\!\n\n📋 Rincian:\n' + rincian + '\n\n💰 Total: Rp ' + escape(total.toLocaleString('id-ID'));
} else {
  const total = items.reduce((sum, i) => sum + i.nominal, 0);
  text = '✅ ' + escape(count) + ' transaksi berhasil dicatat\\!\n\n💰 Total: Rp ' + escape(total.toLocaleString('id-ID'));
}
return [{ json: { summary: text } }];

const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64Image = binaryBuffer.toString('base64');
return [{
  json: {
    body: {
      model: "meta-llama/llama-4-scout-17b-16e-instruct",
      max_tokens: 2000,
      messages: [{
        role: "user",
        content: [
          {
            type: "image_url",
            image_url: {
              url: `data:image/jpeg;base64,${base64Image}`
            }
          },
          {
            type: "text",
            text: "Kamu adalah asisten keuangan. Baca struk/nota ini dengan teliti.\n\nJika ini adalah struk belanja dengan banyak item, catat sebagai 1 transaksi dengan nominal = TOTAL yang dibayar.\n\nIsi setiap field dengan lengkap:\n- vendor: nama toko/restoran yang tertera di struk\n- deskripsi: ringkasan item yang dibeli, contoh: Bread Butter Pudding, Cream Bruille, dll\n- metode_bayar: metode pembayaran yang tertera, contoh: Debit BCA, Cash, OVO\n- dompet: sesuaikan dengan metode bayar, contoh: BCA, OVO, Cash\n- tanggal: tanggal transaksi dari struk\n\nBalas HANYA dengan JSON array murni, tanpa markdown, tanpa penjelasan, tanpa backtick.\n\nFormat:\n[{\"tipe\":\"Pengeluaran\",\"nominal\":0,\"kategori\":\"\",\"sub_kategori\":\"\",\"deskripsi\":\"\",\"tanggal\":\"\",\"dompet\":\"\",\"transfer_ke\":\"\",\"metode_bayar\":\"\",\"sumber_pemasukan\":\"\",\"vendor\":\"\",\"catatan\":\"\",\"tag\":\"\"}]\n\nKategori: BBM, Konsumsi, ATK, Perawatan, Utilitas, Transport, Shopping, Lainnya\nFormat tanggal: YYYY-MM-DD\nNominal harus angka tanpa titik/koma, contoh: 43500\nJika info tidak ada, isi string kosong."
          }
        ]
      }]
    }
  }
}];

